1: const State = enum(u8) {
2:     idle,
3:     one_a,
4:     circumflex,
5:     literal,
6: };
7: 
8: const ProcessKeyEventResult = extern struct {
9:     num_backspaces: u8,
10:     num_chars: u8,
11:     swallow_event: bool,
12:     chars: [*]const u16,
13: };
14: 
15: // --- Internal variables ---
16: 
17: var state: State = .idle;
18: var first_a_upper: bool = false;
19: var gap: u8 = 0;
20: var bufs: [2][2]u16 = .{ .{ 0, 0 }, .{ 0, 0 } };
21: var active: u1 = 0;
22: 
23: const passthrough: ProcessKeyEventResult = .{
24:     .num_backspaces = 0,
25:     .num_chars = 0,
26:     .swallow_event = false,
27:     .chars = @ptrCast(&bufs[0]),
28: };
29: 
30: // --- Internal functions ---
31: 
32: fn emit(num_backspaces: u8, chars: []const u16) ProcessKeyEventResult {
33:     const buf = @as([*]u16, @ptrCast(&bufs[active]));
34:     for (chars, 0..) |c, i| buf[i] = c;
35:     active ^= 1;
36:     return .{
37:         .num_backspaces = num_backspaces,
38:         .num_chars = @intCast(chars.len),
39:         .swallow_event = true,
40:         .chars = buf,
41:     };
42: }
43: 
44: fn is_a(c: u16) bool {
45:     return c == 'a' or c == 'A';
46: }
47: 
48: fn is_alphanumeric(c: u16) bool {
49:     return (c >= '0' and c <= '9') or
50:         (c >= 'A' and c <= 'Z') or
51:         (c >= 'a' and c <= 'z');
52: }
53: 
54: fn handle_a(char_code: u16) ProcessKeyEventResult {
55:     const upper = char_code == 'A';
56:     switch (state) {
57:         .idle => {
58:             state = .one_a;
59:             first_a_upper = upper;
60:             return passthrough;
61:         },
62:         .one_a => {
63:             state = .circumflex;
64:             const c: u16 = if (first_a_upper) 0x00C2 else 0x00E2;
65:             return emit(1, &.{c});
66:         },
67:         .circumflex => {
68:             state = .literal;
69:             const c0: u16 = if (first_a_upper) 'A' else 'a';
70:             const c1: u16 = if (upper) 'A' else 'a';
71:             return emit(1, &.{ c0, c1 });
72:         },
73:         .literal => unreachable,
74:     }
75: }
76: 
77: // --- Public functions ---
78: 
79: export fn reset_state() void {
80:     state = .idle;
81:     first_a_upper = false;
82:     gap = 0;
83: }
84: 
85: export fn process_backspace() ProcessKeyEventResult {
86:     if (gap > 0) {
87:         gap -= 1;
88:     } else switch (state) {
89:         .literal => state = .one_a,
90:         .idle => {},
91:         else => reset_state(),
92:     }
93:     return passthrough;
94: }
95: 
96: export fn process_key_event(char_code: u16) ProcessKeyEventResult {
97:     if (is_a(char_code)) {
98:         if (gap == 0 and state != .literal) return handle_a(char_code);
99:     } else if (!is_alphanumeric(char_code)) {
100:         reset_state();
101:         return passthrough;
102:     } else if (state == .idle) {
103:         return passthrough;
104:     }
105: 
106:     if (gap == 255) {
107:         reset_state();
108:         return passthrough;
109:     }
110:     gap += 1;
111:     return passthrough;
112: }

