fn handle_e(char_code: u16) ProcessKeyEventResult {
    const upper = char_code == 'E';
    switch (state) {
        .idle => {
            state = .one_e;
            first_e_upper = upper;
            return passthrough;
        },
        .one_e => {
            state = .circumflex;
            const c: u16 = if (first_e_upper) 0x00CA else 0x00EA;
            return emit(1, &.{c});
        },
        .circumflex => {
            state = .literal;
            const c0: u16 = if (first_e_upper) 'E' else 'e';
            const c1: u16 = if (upper) 'E' else 'e';
            return emit(1, &.{ c0, c1 });
        },
        .literal => unreachable,
    }
}

